        {"title": "Momaqaldiroq", "ar": "سُبْحَانَ الَّذِي يُسَبِّحُ الرَّعْدُ بِحَمْدِهِ", "lat": "Subhanallaziy yusabbihur-ra'du bihamdihi.", "uz": "Momaqaldiroq hamd aytib tasbeh aytgan Zot pokdir."},
        {"title": "Yangi oy", "ar": "اللَّهُمَّ أَهِلَّهُ عَلَيْنَا بِالْأَمْنِ وَالْإِيمَانِ", "lat": "Allohumma ahillahu 'alayna bil-amni val-iiman.", "uz": "Allohim, buni bizga tinchlik va iymon bilan kirit."},
