        {"title": "Katta tavba", "ar": "أَسْتَغْفِرُ اللهَ الَّذِي لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ", "lat": "Astaghfirullohallaziy la ilaha illa huval-Hayyul-Qoyyum.", "uz": "O'zidan o'zga iloh yo'q, Hayy va Qoyyum bo'lgan Allohdan mag'firat so'rayman."},
        {"title": "Gunohlar uchun", "ar": "اللَّهُمَّ اغْفِرْ لِي خَطِيئَتِي وَجَهْلِي", "lat": "Allohummagh-fir li xoti-ati va jahli.", "uz": "Allohim, xatoyimni, nodonligimni va ishlarimda haddan oshganimni mag'firat qil."},
